tests.source_program:
define i16 @or_disjoint_sext_sext(i8 %x, i4 %y) {
  %sx = sext i8 %x to i16
  %sy = sext i4 %y to i16
  %r = or disjoint i16 %sx, %sy
  ret i16 %r
}

define i16 @or_disjoint_sext_sext_2(i8 %x, i8 %y) {
  %sx = sext i8 %x to i16
  %sy = sext i8 %y to i16
  %r = or disjoint i16 %sx, %sy
  ret i16 %r
}

define i16 @or_disjoint_zext_zext(i8 %x, i4 %y) {
  %zx = zext i8 %x to i16
  %zy = zext i4 %y to i16
  %r = or disjoint i16 %zy, %zx
  ret i16 %r
}

define i16 @or_disjoint_zext_zext_2(i8 %x, i8 %y) {
  %zx = zext i8 %x to i16
  %zy = zext i8 %y to i16
  %r = or disjoint i16 %zy, %zx
  ret i16 %r
}

define i16 @xor_sext_sext(i8 %x, i4 %y) {
  %sx = sext i8 %x to i16
  %sy = sext i4 %y to i16
  %r = xor i16 %sx, %sy
  ret i16 %r
}

define <2 x i16> @xor_zext_zext(<2 x i8> %x, <2 x i4> %y) {
  %zx = zext <2 x i8> %x to <2 x i16>
  %zy = zext <2 x i4> %y to <2 x i16>
  %r = xor <2 x i16> %zx, %zy
  ret <2 x i16> %r
}
